mapper.select:
/* IfWcsOutBoundMapper.selectOrderPickingCancel - WCS주문피킹 취소 정보 */
SELECT DISTINCT SOBWCS.CTKEY
     , SOBWCS.OWKEY
	 , SOBWCS.OBHDKEY
  FROM TWORK_INTF_SOBWCS SOBWCS
 WHERE SOBWCS.REQ_TYPE_CD = 'D'
   AND EXISTS (
		SELECT 1
		  FROM TWORK_INTF_ROBWCS ROBWCS
		 WHERE ROBWCS.R_OB_SEQ  = #{rObSeq}
		   AND ROBWCS.STATUS    = #{status}
		   AND ROBWCS.OB_NUMBER = SOBWCS.OB_NUMBER
   )

mapper.update:
/* IfWcsOutBoundMapper.updateInterfaceStatus - WCS 출고주문 상태 변경 */
UPDATE TWORK_INTF_SOBWCS
   SET SUCCEEDED = 'false'
     , OB_NUMBER = '*' || OB_NUMBER
 WHERE OB_SEQ = #{OB_SEQ}

/* IfWcsOutBoundMapper.updateReplenishmentInterfaceStatus - WCS 보충지시 상태 변경 */
UPDATE TWORK_INTF_SRMWCS
   SET SUCCEEDED = 'false'
     , RM_NUMBER = '*' || RM_NUMBER
 WHERE RM_SEQ = #{RM_SEQ}
